expressions.expression:
X = [];
Y = [];
xx = double(TimeValues);
yy = double(OutValues);
if min(xx) < 0
  error('Negative Time Values are not supported.');
  xx = [];
elseif min(xx) > 0
  xx(2:(end+1)) = xx;
  xx(1) = 0;
  yy(2:(end+1)) = yy;
end
if tsamp == -1
  tsamp = min(diff(xx));
end
nn = floor(max(xx)/double(tsamp));

[X, Y] = genRepeatingSequenceInterpolatedBlockIconData(xx, yy, LookUpMeth);

LookupMethod = get_param(gcb, 'LookupMeth');

switch LookupMethod
    case 'Interpolation-Use End Values'
        set_param([gcb, '/Lookup'], 'InterpMethod', 'Linear');
        set_param([gcb, '/Lookup'], 'ExtrapMethod', 'Clip');
    case 'Use Input Nearest'
        set_param([gcb, '/Lookup'], 'InterpMethod', 'Nearest');
    case 'Use Input Below'
        set_param([gcb, '/Lookup'], 'InterpMethod', 'Flat');    
    case 'Use Input Above'
        set_param([gcb, '/Lookup'], 'InterpMethod', 'Above');  
end

if PowerInvariant==0
    K1 = 0.5;
    K2 = 2/3;
else
    K1 = 1/sqrt(2);
    K2 = sqrt(2/3);
end

switch AxisAlignment
    case 'Q-axis'
        Offset = 0;
    case 'D-axis'
        Offset = pi/2;
    otherwise
end

