Tsw = 1/fsw;

if fsw <= 0
    error(message('physmod:simscape:compiler:patterns:checks:GreaterThanZero',getString(message('physmod:ee:library:comments:control:eePwmGeneratorTwoLevel:SwitchingFrequencyHz_MP'))));
end

if Ts <= 0
    error(message('physmod:simscape:compiler:patterns:checks:GreaterThanZero',getString(message('physmod:ee:library:comments:control:eePwmGeneratorTwoLevel:SampleTimes_MP'))));
end

if Ts > 1/(10*fsw)
    error(message('physmod:simscape:compiler:patterns:checks:LessThanOrEqual',getString(message('physmod:ee:library:comments:control:eePwmGeneratorTwoLevel:SampleTimes_MP')),getString(message('physmod:ee:library:comments:control:eePwmGeneratorTwoLevel:inverseOf10TimesSwitchingFrequency_MP'))));
end

switch SamplingMode
    case 'Natural'
        RateTransitionOnInput = -1;
        GateGeneratorX0 = 0;
    case 'Asymmetric'
        RateTransitionOnInput = 0.5*Tsw;
        GateGeneratorX0 = 0.5/fsw;
    case 'Symmetric'
        RateTransitionOnInput = Tsw;
        GateGeneratorX0 = 0;
end


switch PWMMode
    case 'Continuous PWM (CPWM)'
        switch CPWMMode
            case 'SPWM: sinusoidal PWM'
                PWM = 1;
            case 'SVM: space vector modulation'
                PWM = 2;
        end
    case 'Discontinuous PWM (DPWM)'
        switch DPWMMode
            case '60 DPWM: 60 degree discontinuous PWM'
                PWM = 3;
            case '60 DPWM (+30 degree shift): +30 degree shift from 60 DPWM'
                PWM = 4;
            case '60 DPWM (-30 degree shift): -30 degree shift from 60 DPWM'
                PWM = 5;
            case '30 DPWM: 30 degree discontinuous PWM'
                PWM = 6;
            case '120 DPWM: positive dc component'
                PWM = 7;
            case '120 DPWM: negative dc component'
                PWM = 8;
        end
end

if PowerInvariant==0
    K1 = 0.5;
    K2 = 2/3;
else
